            id: journalId,
            title: journalTitle
        }
        setJournalData(data);
        setShowEditor(showEditor === journalId ? null : journalId);
    }

    const handleClickCloseEditor = () => {
        setShowEditor(null)
    }

    useEffect(() =>{
        console.log(data)
    }, [data])

    useEffect(() =>{
