            fetchNextPage();
        }
    }, [fetchNextPage, isLoadingMore, inView])

    const handleToggleView = useCallback(() => {
        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
    }, []);


    const journals = data?.pages.flatMap((page) => page.data) || [];
    if(isLoading){
        return(
