}

export default VisitedProfilePostCards;

import React, { useMemo } from 'react';
import { parseCanvasDoc } from '../../../../utils/canvasDoc';
import './canvaspreview.css';

const FONT_MAP = {
    serif: 'Georgia, serif',
    mono: 'Courier New, monospace',
    handwritten: 'Comic Sans MS, cursive',
    bold: 'Trebuchet MS, sans-serif',
};

const CanvasPreview = ({ canvasDoc }) => {
    const parsed = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);

    const { meta, snippets, images } = parsed;
    const isEmpty = snippets.length === 0 && images.length === 0;
    const isDark = meta.theme === 'dark';
    const aspectClass = meta.aspectRatio === '4:5' ? 'is-4-5' : 'is-1-1';

    const allElements = useMemo(() => {
        const items = [];

        snippets.forEach((s) => {
            items.push({ type: 'snippet', zIndex: s.zIndex, data: s });
        });

        images.forEach((img) => {
            items.push({ type: 'image', zIndex: img.zIndex, data: img });
        });

        items.sort((a, b) => a.zIndex - b.zIndex);
        return items;
    }, [snippets, images]);

    return (
        <div
            className={`canvas-preview ${isDark ? 'is-dark' : 'is-light'} ${aspectClass}`}
            aria-hidden="true"
        >
            <div className="canvas-preview-dots" />

            {isEmpty ? (
                <span className="canvas-preview-empty">Canvas</span>
            ) : (
                allElements.map((el) => {
                    if (el.type === 'snippet') {
                        const s = el.data;
                        const truncated = s.text.length > 80 ? `${s.text.substring(0, 80)}...` : s.text;
                        return (
                            <span
                                key={s.id}
                                className="canvas-preview-snippet"
                                style={{
                                    left: `${s.x * 100}%`,
                                    top: `${s.y * 100}%`,
                                    zIndex: s.zIndex,
                                    fontFamily: FONT_MAP[s.fontStyle] || FONT_MAP.serif,
                                    transform: `rotate(${s.rotation}deg) scaleX(${s.scaleX}) scale(${s.sizeScale * 0.45})`,
                                }}
                            >
                                {truncated}
                            </span>
                        );
                    }

                    const img = el.data;
                    if (!img.src) return null;
                    return (
                        <img
                            key={img.id}
                            className="canvas-preview-image"
                            src={img.src}
                            alt=""
                            loading="lazy"
                            draggable={false}
                            style={{
                                left: `${img.x * 100}%`,
                                top: `${img.y * 100}%`,
                                width: `${img.width * 100}%`,
                                zIndex: img.zIndex,
                                transform: `rotate(${img.rotation}deg) scaleX(${img.scaleX})`,
                            }}
                        />
                    );
                })
            )}
        </div>
    );
};

export default CanvasPreview;

/* ── Canvas Preview Thumbnail ── */
.canvas-preview {
    position: relative;
    width: 100%;
    max-height: 220px;
    overflow: hidden;
    border-bottom: 1px solid var(--border-card);
    pointer-events: none;
    user-select: none;
    border-radius: 12px 12px 0 0;
}

.canvas-preview.is-1-1 {
    aspect-ratio: 1 / 1;
}

.canvas-preview.is-4-5 {
    aspect-ratio: 4 / 5;
}

.canvas-preview.is-light {
    background-color: #FAFAFA;
}

.canvas-preview.is-dark {
    background-color: #1A1A1A;
}

/* Grid dot pattern overlay */
.canvas-preview-dots {
    position: absolute;
    inset: 0;
    z-index: 0;
    opacity: 0.35;
    background-image: radial-gradient(circle, currentColor 0.6px, transparent 0.6px);
    background-size: 16px 16px;
}

.canvas-preview.is-light .canvas-preview-dots {
    color: #c0c0c0;
}

.canvas-preview.is-dark .canvas-preview-dots {
    color: #444;
}

/* Snippet text */
.canvas-preview-snippet {
    position: absolute;
    max-width: 60%;
    font-size: 11px;
    line-height: 1.3;
    white-space: pre-wrap;
    word-break: break-word;
    transform-origin: top left;
}

.canvas-preview.is-light .canvas-preview-snippet {
    color: #1a1a1a;
}

.canvas-preview.is-dark .canvas-preview-snippet {
    color: #e8e8e8;
}

/* Image element */
.canvas-preview-image {
    position: absolute;
    object-fit: cover;
    border-radius: 3px;
    transform-origin: top left;
}

/* Empty state */
.canvas-preview-empty {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    font-size: 13px;
    font-weight: 500;
    letter-spacing: 0.04em;
    opacity: 0.3;
}

.canvas-preview.is-light .canvas-preview-empty {
    color: #555;
}

.canvas-preview.is-dark .canvas-preview-empty {
    color: #aaa;
}

/* ── Canvas Card Accent ── */
.cards.is-canvas-card {
    border-color: color-mix(in srgb, var(--accent-purple) 30%, var(--border-card));
}

.cards.is-canvas-card:hover {
    box-shadow: 0 0 12px 0 color-mix(in srgb, var(--accent-purple) 15%, transparent);
}

/* Grid view canvas accent */
.postcards-grid-item.is-canvas-card {
    border-color: color-mix(in srgb, var(--accent-purple) 30%, var(--border-card));
}

.postcards-grid-item.is-canvas-card:hover {
    box-shadow: 0 0 12px 0 color-mix(in srgb, var(--accent-purple) 15%, transparent);
}

/* Grid view: canvas preview inside grid img wrap */
.postcards-grid-img-wrap .canvas-preview {
    max-height: 140px;
    border-radius: 10px 10px 0 0;
    border-bottom: none;
}

/* Profile list view canvas accent */
.profile-postcards.is-canvas-card {
    border-color: color-mix(in srgb, var(--accent-purple) 30%, var(--border-card));
}

.profile-postcards.is-canvas-card:hover {
    box-shadow: 0 0 12px 0 color-mix(in srgb, var(--accent-purple) 15%, transparent);
}

/* ── Mobile ── */
@media (max-width: 480px) {
    .canvas-preview {
        max-height: 160px;
        border-radius: 10px 10px 0 0;
    }
}

